column101:
const datos = $input.all();

// Generar filas de la tabla
let filas = '';
for (const item of datos) {
  const d = item.json;
  let colorClase = '';
  if (d.estado === '✅ Al día') {
    colorClase = 'background-color: #d4edda;';
  } else if (d.estado === '⚠️ Advertencia') {
    colorClase = 'background-color: #fff3cd;';
  } else {
    colorClase = 'background-color: #f8d7da;';
  }

  filas += `
    <tr style="${colorClase}">
      <td style="border: 1px solid #ddd; padding: 10px;">${d.ID}</td>
      <td style="border: 1px solid #ddd; padding: 10px;">${d.Nombre}</td>
      <td style="border: 1px solid #ddd; padding: 10px;">${d.diasLaborables}</td>
      <td style="border: 1px solid #ddd; padding: 10px;">${d.horasEsperadas}</td>
      <td style="border: 1px solid #ddd; padding: 10px;">${d.horasIngresadas}</td>
      <td style="border: 1px solid #ddd; padding: 10px;">${d.diferencia}</td>
      <td style="border: 1px solid #ddd; padding: 10px;">${d.porcentaje}%</td>
      <td style="border: 1px solid #ddd; padding: 10px;">${d.estado}</td>
      <td style="border: 1px solid #ddd; padding: 10px;">${d.cantidadRegistros}</td>
    </tr>
  `;
}

// Calcular estadísticas
const total = datos.length;
const alDia = datos.filter(d => d.json.estado === '✅ Al día').length;
const advertencia = datos.filter(d => d.json.estado === '⚠️ Advertencia').length;
const atrasados = datos.filter(d => d.json.estado === '❌ Atrasado').length;

const htmlCompleto = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
</head>
<body style="font-family: Arial, sans-serif; padding: 20px;">
  <h2>📊 Reporte de Horas</h2>
  <p>Período: Enero 2026</p>

  <div style="background-color: #f0f0f0; padding: 15px; border-radius: 5px; margin: 20px 0;">
    <h3 style="margin-top: 0;">Resumen General</h3>
    <p><strong>Total colaboradores:</strong> ${total}</p>
    <p>✅ Al día: ${alDia} (${((alDia/total)*100).toFixed(1)}%)</p>
    <p>⚠️ Advertencia: ${advertencia} (${((advertencia/total)*100).toFixed(1)}%)</p>
    <p>❌ Atrasados: ${atrasados} (${((atrasados/total)*100).toFixed(1)}%)</p>
  </div>

  <table style="border-collapse: collapse; width: 100%; margin: 20px 0;">
    <thead>
      <tr>
        <th style="background-color: #4CAF50; color: white; padding: 12px; text-align: left;">ID</th>
        <th style="background-color: #4CAF50; color: white; padding: 12px; text-align: left;">Nombre</th>
        <th style="background-color: #4CAF50; color: white; padding: 12px; text-align: left;">Días Lab.</th>
        <th style="background-color: #4CAF50; color: white; padding: 12px; text-align: left;">Hrs Esperadas</th>
        <th style="background-color: #4CAF50; color: white; padding: 12px; text-align: left;">Hrs Ingresadas</th>
        <th style="background-color: #4CAF50; color: white; padding: 12px; text-align: left;">Diferencia</th>
        <th style="background-color: #4CAF50; color: white; padding: 12px; text-align: left;">Porcentaje</th>
        <th style="background-color: #4CAF50; color: white; padding: 12px; text-align: left;">Estado</th>
        <th style="background-color: #4CAF50; color: white; padding: 12px; text-align: left;">Registros</th>
      </tr>
    </thead>
    <tbody>
      ${filas}
    </tbody>
  </table>

  <p style="font-size: 12px; color: #666;">
    Semana laboral: Lunes a Jueves 8hrs, Viernes 6.5hrs = 38.5hrs/semana
  </p>
  <p style="font-size: 11px; color: #999;">Reporte generado automáticamente</p>
</body>
</html>`;

return {
  htmlContent: htmlCompleto
};

