// Obtener fecha actual (ejecución)
const now = new Date();

// Inicio del mes en curso
const startDate = new Date(now.getFullYear(), now.getMonth(), 1);

// Fin del período: AYER (se excluye el día actual)
const endDate = new Date(now.getFullYear(), now.getMonth(), now.getDate() - 1);

// Mapeo de meses a formato requerido
const MONTHS = ["ENE","FEB","MAR","ABR","MAY","JUN","JUL","AGO","SEP","OCT","NOV","DIC"];
const MES_CURSO = MONTHS[now.getMonth()];

// Contadores
let CONT_HAB_LUJU = 0;
let CONT_HAB_VI = 0;

// Iterar día por día
for (let d = new Date(startDate); d <= endDate; d.setDate(d.getDate() + 1)) {
  const day = d.getDay();
  // 1=Lunes, 2=Martes, 3=Miércoles, 4=Jueves, 5=Viernes

  if (day >= 1 && day <= 4) {
    CONT_HAB_LUJU++;
  } else if (day === 5) {
    CONT_HAB_VI++;
  }
}

// Cálculo de horas
const CONT_HORA_LUJU = CONT_HAB_LUJU * 8;
const CONT_HORA_VI = CONT_HAB_VI * 6.5;
const CONT_TOTAL = CONT_HORA_LUJU + CONT_HORA_VI;

// Salida
return [
  {
    json: {
      MES_CURSO,
      CONT_HAB_LUJU,
      CONT_HAB_VI,
      CONT_HORA_LUJU,
      CONT_HORA_VI,
      CONT_TOTAL
    }
  }
]

const hoy = new Date();
hoy.setMinutes(hoy.getMinutes() + hoy.getTimezoneOffset() + 180);

const fechaFin = new Date(hoy);
fechaFin.setDate(fechaFin.getDate() - 1);
while (fechaFin.getDay() === 0 || fechaFin.getDay() === 6) {
  fechaFin.setDate(fechaFin.getDate() - 1);
}

const fechaInicio = new Date(fechaFin.getFullYear(), fechaFin.getMonth(), 0);
while (fechaInicio.getDay() !== 5) {
  fechaInicio.setDate(fechaInicio.getDate() - 1);
