column166:
const repo = $input.first().json;
const inicio = new Date(repo.fechaInicio);
const fin = new Date(repo.fechaFin);

let diasLaborables = 0;
let horasTotales = 0;

for (let d = new Date(inicio); d <= fin; d.setDate(d.getDate() + 1)) {
  const dia = d.getDay();
  if (dia >= 1 && dia <= 4) { diasLaborables++; horasTotales += 8; }
  else if (dia === 5) { diasLaborables++; horasTotales += 6.5; }
}

return {
  json: {
    diasLaborables,
    horasTotales: +horasTotales.toFixed(1),
    personas: repo.personas,
    mesCurso: repo.mesCurso,
    fechaInicio: repo.fechaInicio,
    fechaFin: repo.fechaFin,
    periodoTexto: repo.periodoTexto
  }
};

column178:
const apiData = $input.first().json;
const registros = apiData.time || [];

const calc2 = $('Calculo de horas1').first().json;
const personasArray = calc2.personas;
const diasLaborables = calc2.diasLaborables;
const horasEsperadas = calc2.horasTotales;
const mesCurso = calc2.mesCurso;

const horasPorPersona = {};
for (const r of registros) {
  const pid = Number(r.personid);
  horasPorPersona[pid] = (horasPorPersona[pid] || 0) + Number(r.time || 0);
}

const resultados = personasArray.map(p => {
  const nombre = `${p.nombre} ${p.apellidoP} ${p.apellidoM || ''}`.trim();
  const horasIngresadas = +(horasPorPersona[p.personId] || 0).toFixed(1);
  const diferencia = +(horasEsperadas - horasIngresadas).toFixed(1);
  const porcentaje = horasEsperadas > 0 ? Math.round((horasIngresadas / horasEsperadas) * 100) : 0;
  const estado = porcentaje >= 100 ? '✅ Al día' : porcentaje >= 80 ? '⚠️ Pendiente' : '❌ Atrasado';

  return {
    Area: p.area,
    Nombre: nombre,
    horasEsperadas: +horasEsperadas.toFixed(1),
    horasIngresadas,
    diferencia,
    semanasPendientes: diferencia > 0 ? +((diferencia / 40).toFixed(1)) : 0,
    porcentaje,
    estado,
    mesCurso,
    diasLaborables
  };
});

return resultados.sort((a, b) => a.diferencia - b.diferencia);

column185:
const datos = $input.all();
const calc = $('Calculo de horas1').first().json;

const periodoInicio = calc.fechaInicio;
const periodoFin = calc.fechaFin;
const diasLaborables = datos.length ? datos[0].json.diasLaborables : 0;
const horasEsperadasPeriodo = datos.length ? datos[0].json.horasEsperadas : 0;
const totalColaboradores = datos.length;

const alDia = datos.filter(i => i.json.estado === '✅ Al día').length;
const pendientes = datos.filter(i => i.json.estado === '⚠️ Pendiente').length;
const atrasados = datos.filter(i => i.json.estado === '❌ Atrasado').length;

const htmlCompleto = `
<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body style="margin:0;padding:8px 10px;font-family:Arial,APTOS,sans-serif;font-size:12px;">

<h2 style="color:#7049BC;font-size:14px;margin:0;">
  <strong>Reporte de Horas – ${datos[0]?.json.mesCurso || ''}</strong>
</h2>

<p style="margin:8px 0;">Estimad@s, esperamos que este mensaje les encuentre bien:</p>

<p style="margin:8px 0;">Como formalidad semanal, se comparte el reporte de ingreso de horas correspondiente
al período entre las fechas: <strong>${calc.periodoTexto}</strong>.</p>

<p style="margin:12px 0;">
  <span style="display:inline-block;background:#5CDB82;padding:10px;color:#000;">
    <strong>Nota:</strong> al momento de registrar las horas y su respectiva descripción,
    se solicita no utilizar signos especiales (como ", &, %, entre otros),
    ya que estos afectan la reportería.
  </span>
</p>

<table width="100%" cellpadding="0" cellspacing="0" border="1" bordercolor="#5838A3"
  style="width:100%;max-width:900px;border-collapse:collapse;font-size:12px;margin-top:15px;text-align:center;">
<thead><tr>
  ${['Área','Colaborador','Horas Esperadas','Horas Ingresadas','Diferencia','Porcentaje','Estado','Semanas Pendientes'].map(h =>
    `<th bgcolor="#7049BC" style="border:1px solid #5838A3;color:#ffffff;padding:6px 4px;font-weight:bold;text-align:center;vertical-align:middle;">${h}</th>`
  ).join('')}
</tr></thead>
<tbody>
${datos.map(d => {
  const colorFila = d.json.estado === '✅ Al día' ? '#C9D6CC' : d.json.estado === '⚠️ Pendiente' ? '#E8DFC7' : '#F4CCCC';
  const colorBorde = d.json.estado === '✅ Al día' ? '#8BA88F' : d.json.estado === '⚠️ Pendiente' ? '#D4BC8E' : '#E89A9A';
  const td = (val, bold=false) => `<td bgcolor="${colorFila}" style="padding:0;height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">${bold ? `<strong>${val}</strong>` : val}</td>`;
  return `<tr>
    ${td(d.json.Area)}
    ${td(d.json.Nombre, true)}
    ${td(d.json.horasEsperadas, true)}
    ${td(d.json.horasIngresadas, true)}
    ${td(Math.abs(d.json.diferencia))}
    ${td(d.json.porcentaje + '%')}
    ${td(d.json.estado, true)}
    ${td(d.json.semanasPendientes)}
  </tr>`;
}).join('')}
</tbody></table>

<p style="color:#7049BC;font-weight:bold;margin-top:18px;font-size:14px;">Alcances del Reporte:</p>
<ul style="margin:0;padding-left:18px;">
  <li><strong>Fecha inicio:</strong> ${periodoInicio}</li>
  <li><strong>Fecha fin:</strong> ${periodoFin}</li>
  <li><strong>Días hábiles considerados:</strong> ${diasLaborables}</li>
  <li><strong>Cantidad de horas contabilizadas en el mes:</strong> ${horasEsperadasPeriodo}</li>
  <li><strong>Total colaboradores:</strong> ${totalColaboradores}</li>
  <li><strong>Colaboradores al día:</strong> ${alDia}</li>
  <li><strong>Colaboradores pendientes:</strong> ${pendientes}</li>
  <li><strong>Colaboradores atrasados:</strong> ${atrasados}</li>
</ul>

<p style="margin-top:16px;">Frente a dudas, consultas o validación de métricas, comunicarse directamente
con el <strong>área de control de gestión</strong>.</p>

