// ===============================
// FECHA ACTUAL (CHILE)
// ===============================
const hoy = new Date();
const offsetChile = -3 * 60;
hoy.setMinutes(hoy.getMinutes() + hoy.getTimezoneOffset() - offsetChile);

// ===============================
// FECHA FIN = DÍA HÁBIL ANTERIOR
// ===============================
const fechaFin = new Date(hoy);
fechaFin.setDate(fechaFin.getDate() - 1);

// Si cae sábado o domingo, retroceder
while (fechaFin.getDay() === 0 || fechaFin.getDay() === 6) {
  fechaFin.setDate(fechaFin.getDate() - 1);
}

// ===============================
// MES ETIQUETA (SEGÚN FECHA FIN)
// ===============================
const MESES = [
  'ENE','FEB','MAR','ABR','MAY','JUN',
  'JUL','AGO','SEP','OCT','NOV','DIC'
];

const mesEtiqueta = MESES[fechaFin.getMonth()];

// ===============================
// FECHA INICIO = PRIMER DÍA HÁBIL DEL MES
// ===============================
const fechaInicio = new Date(fechaFin.getFullYear(), fechaFin.getMonth(), 1);

// Si cae sábado → lunes
if (fechaInicio.getDay() === 6) {
  fechaInicio.setDate(fechaInicio.getDate() + 2);
}

// Si cae domingo → lunes
if (fechaInicio.getDay() === 0) {
  fechaInicio.setDate(fechaInicio.getDate() + 1);
}

// ===============================
// FORMATO YYYY-MM-DD
// ===============================
