// ===============================
// FUENTES DE DATOS
// ===============================
const datos = $input.all();
const repo = $('Repositorio').first().json;

// ===============================
// FECHAS Y METADATA
// ===============================
const periodoInicio = repo.fechaInicio;
const periodoFin = repo.fechaFin;

const mesCurso = datos.length ? datos[0].json.mesCurso : '';
const diasLaborables = datos.length ? datos[0].json.diasLaborables : 0;

// ===============================
// MÉTRICAS GENERALES
// ===============================
const totalColaboradores = datos.length;
const alDia = datos.filter(i => i.json.estado === '✅ Al día').length;
const advertencia = datos.filter(i => i.json.estado === '⚠️ Advertencia').length;
const atrasados = datos.filter(i => i.json.estado === '❌ Atrasado').length;

// ===============================
// FORMATEO FECHAS ES
// ===============================
const MESES = [
  'enero','febrero','marzo','abril','mayo','junio',
  'julio','agosto','septiembre','octubre','noviembre','diciembre'
];

function formatearFechaES(fechaISO) {
  const [yyyy, mm, dd] = fechaISO.split('-');
  return `${dd} de ${MESES[Number(mm) - 1]}`;
}

const periodoTexto =
  `${formatearFechaES(periodoInicio)} al ${formatearFechaES(periodoFin)}`;

// ===============================
// FILAS TABLA
// ===============================
let filas = '';

for (const item of datos) {
  const d = item.json;

  const colorFila =
    d.estado === '✅ Al día' ? '#e8f5e9' :
    d.estado === '⚠️ Advertencia' ? '#fff8e1' :
    '#fdecea';

  filas += `
  <tr style="background:${colorFila};">
    <td><strong>${d.Area}</strong></td>
    <td><strong>${d.Nombre}</strong></td>
    <td><strong>${d.horasEsperadas}</strong></td>
    <td><strong>${d.horasIngresadas}</strong></td>
    <td><strong>${Math.abs(d.diferencia)}</strong></td>
    <td><strong>${Math.round(d.porcentaje)}%</strong></td>
    <td><strong>${d.estado}</strong></td>
    <td><strong>${d.semanasPendientes}</strong></td>
  </tr>`;
}

// ===============================
// HTML FINAL
// ===============================
const htmlCompleto = `
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
</head>

<body style="font-family:APTOS,Arial,sans-serif;font-size:12px;padding:20px;">

<h2 style="color:#7049BC;font-size:14px;">
  <strong>Reporte de Horas – ${mesCurso}</strong>
</h2>

<p>
  Estimad@s, esperamos que este mensaje les encuentre bien:
</p>

<p>
  Como formalidad semanal, se comparte el reporte de ingreso de horas correspondiente
  al período entre las fechas: <strong>${periodoTexto}</strong>.
</p>

<p>
  <span style="display:inline-block;background:#5CDB82;padding:10px;color:#000000;">
    <strong>Nota:</strong> al momento de registrar las horas y su respectiva descripción,
    se solicita no utilizar signos especiales (como “, &, %, entre otros),
    ya que estos afectan la reportería.
  </span>
</p>

<table
  cellpadding="0"
  cellspacing="0"
  style="
    width:100%;
    max-width:900px;
    border-collapse:collapse;
    font-size:12px;
    margin-top:15px;
    text-align:center;
  "
>
<thead>
<tr style="background:#7049BC;color:#fff;">
  <th style="vertical-align:middle;">Área</th>
  <th style="vertical-align:middle;">Colaborador</th>
  <th style="vertical-align:middle;">Horas<br>Esperadas</th>
  <th style="vertical-align:middle;">Horas<br>Ingresadas</th>
  <th style="vertical-align:middle;">Diferencia</th>
  <th style="vertical-align:middle;">Porcentaje</th>
  <th style="vertical-align:middle;">Estado</th>
  <th style="vertical-align:middle;">Semanas<br>Pendientes</th>
</tr>
</thead>

<tbody>
${filas}
</tbody>
</table>

<style>
  th, td {
    padding: 8px;
    text-align: center;
    vertical-align: middle;
  }
</style>

<p style="color:#7049BC;font-weight:bold;margin-top:15px;font-size:14px;">
  Alcances del reporte:
</p>

<ul style="margin:0;padding-left:16px;">
  <li><strong>Fecha inicio:</strong> ${periodoInicio}</li>
  <li><strong>Fecha fin:</strong> ${periodoFin}</li>
  <li><strong>Días hábiles considerados:</strong> ${diasLaborables}</li>
  <li><strong>Total colaboradores:</strong> ${totalColaboradores}</li>
  <li><strong>Al día:</strong> ${alDia}</li>
  <li><strong>Advertencia:</strong> ${advertencia}</li>
  <li><strong>Atrasados:</strong> ${atrasados}</li>
</ul>

<p style="margin-top:16px;">
  Frente a dudas, consultas o validación de métricas, comunicarse directamente
  con el <strong>área de control de gestión</strong>.
