// ===============================
// FUENTES DE DATOS
// ===============================
const datos = $input.all();
const repo = $('Repositorio').first().json;


// ===============================
// METADATA DEL REPORTE
// ===============================
const periodoInicio = repo.fechaInicio;
const periodoFin = repo.fechaFin;

// Valores globales (se repiten en todos los registros)
const diasLaborables =
  datos.length ? datos[0].json.diasLaborables : 0;

const horasEsperadasPeriodo =
  datos.length && !isNaN(datos[0].json.horasEsperadas)
    ? datos[0].json.horasEsperadas
    : 0;

const totalColaboradores = datos.length;


// ===============================
// RESUMEN ESTADÍSTICO
// ===============================
const alDia = datos.filter(i =>
  i.json.estado === '✅ Al día'
).length;

const pendientes = datos.filter(i =>
  i.json.estado === '⚠️ Pendiente'
).length;

const atrasados = datos.filter(i =>
  i.json.estado === '❌ Atrasado'
).length;


// ===============================
// HTML FINAL
// ===============================
const htmlCompleto = `
