  </span>
</p>

<table
  width="100%"
  cellpadding="0"
  cellspacing="0"
  border="1"
  bordercolor="#5838A3"
  style="
    width:100%;
    max-width:900px;
    border-collapse:collapse;
    font-size:12px;
    margin-top:15px;
    text-align:center;
  "
>

<thead>
<tr>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:3px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Área
  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Colaborador
  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Horas Esperadas
  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Horas Ingresadas
  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
