  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Semanas Pendientes
  </th>

</tr>
</thead>

<tbody>
${datos.map(d => {

  const colorFila =
    d.json.estado === '✅ Al día' ? '#C9D6CC' :
    d.json.estado === '⚠️ Pendiente' ? '#E8DFC7' :
    '#F4CCCC';

  const colorBorde =
    d.json.estado === '✅ Al día' ? '#8BA88F' :
    d.json.estado === '⚠️ Pendiente' ? '#D4BC8E' :
    '#E89A9A';

  return `
