// =====================================================
// CÁLCULO DE DÍAS LABORABLES Y HORAS ESPERADAS
// =====================================================

const repo = $input.first().json;
const inicio = new Date(repo.fechaInicio);
const fin = new Date(repo.fechaFin);

let diasLaborables = 0;
let horasTotales = 0;

for (let d = new Date(inicio); d <= fin; d.setDate(d.getDate() + 1)) {

  const dia = d.getDay();

  if (dia >= 1 && dia <= 4) {
    diasLaborables++;
    horasTotales += 8;
  } else if (dia === 5) {
    diasLaborables++;
    horasTotales += 6.5;
  }
}

return {
  json: {
    diasLaborables,
    horasTotales: +horasTotales.toFixed(1),
    mesCurso: repo.mesCurso
  }
};

column98:
const repo = $('S01_Variables_Globales1').first().json;
const hoy = new Date(repo.fechaEjecucion);

let fechaFin = new Date(hoy);
fechaFin.setDate(fechaFin.getDate() - 1);
while (fechaFin.getDay() === 0 || fechaFin.getDay() === 6) {
  fechaFin.setDate(fechaFin.getDate() - 1);
}

let contador = 1;
let fechaInicio = new Date(fechaFin);
while (contador < repo.diasObjetivo) {
  fechaInicio.setDate(fechaInicio.getDate() - 1);
  const dia = fechaInicio.getDay();
  if (dia >= 1 && dia <= 5) contador++;
}

return [{
  json: {
    fechaInicioPeriodo: fechaInicio.toISOString().split('T')[0],
    fechaFinPeriodo: fechaFin.toISOString().split('T')[0]
  }
}];

