column676:
const tablaItems = $input.all();
const apiData    = $('S03_Llamar_API_Intervals1').first().json;
const periodoItem = $('R03_Calcular_Horas_Base1').first().json;
const varItem    = $('S01_Variables_Globales1').first().json;

const registros = (apiData.time || []).map(r => ({ ...r, person: decodeHtml(r.person) }));

const horasGlobales  = Number(periodoItem.horasEsperadasPeriodo);
const fechaInicio    = periodoItem.fechaInicio;
const fechaFin       = periodoItem.fechaFin;
const fechaEjecucion = varItem.fechaEjecucion;
const anioActual     = varItem.anioActual;
const diasObjetivo   = varItem.diasObjetivo;

const fi = new Date(fechaInicio);
const ff = new Date(fechaFin);

function decodeHtml(str) {
  if (!str) return '';
  return str
    .replace(/&aacute;/g, 'á').replace(/&eacute;/g, 'é')
    .replace(/&iacute;/g, 'í').replace(/&oacute;/g, 'ó')
    .replace(/&uacute;/g, 'ú').replace(/&Aacute;/g, 'Á')
    .replace(/&Eacute;/g, 'É').replace(/&Iacute;/g, 'Í')
    .replace(/&Oacute;/g, 'Ó').replace(/&Uacute;/g, 'Ú')
    .replace(/&ntilde;/g, 'ñ').replace(/&Ntilde;/g, 'Ñ')
    .replace(/&uuml;/g, 'ü').replace(/&amp;/g, '&');
}

function limpiar(t) {
  if (!t) return '';
  return t.toString()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, '')
    .trim();
}

function primPalabras(nombre, n) {
  return nombre.split(/\s+/).slice(0, n).join(' ');
}

const consolidado = {};

for (const item of tablaItems) {
  const row = item.json;
  if (!row.NOMBRE) continue;
  const esActivo      = row.ACTIVO === true || row.ACTIVO === 1 || String(row.ACTIVO).toLowerCase() === 'true';
  const debeMostrarse = row.SHOW   === true || row.SHOW   === 1 || String(row.SHOW).toLowerCase()   === 'true';
  const esNuevo       = row.NEW_COLAB === true || row.NEW_COLAB === 1 || String(row.NEW_COLAB).toLowerCase() === 'true';
  if (!esActivo || !debeMostrarse) continue;

  let horasEsperadas = horasGlobales;
  if (esNuevo && row.FECHA_INICIO) {
    const inicioColab    = new Date(row.FECHA_INICIO.split('T')[0]);
    const inicioEfectivo = inicioColab > fi ? inicioColab : fi;
    let horasP = 0;
    for (let d = new Date(inicioEfectivo); d <= ff; d.setDate(d.getDate() + 1)) {
      const dia = d.getDay();
      if (dia >= 1 && dia <= 4) horasP += 8;
      else if (dia === 5) horasP += 6.5;
    }
    horasEsperadas = Math.round(horasP * 10) / 10;
  }

  const nLimpio = limpiar(row.NOMBRE);
  consolidado[nLimpio] = {
    Nombre: row.NOMBRE, NOMBRE: row.NOMBRE, NombreLimpio: nLimpio,
    AREA: row.AREA || 'Sin Área', NEW_COLAB: esNuevo, ACTIVO: esActivo,
    FECHA_INICIO: row.FECHA_INICIO ? row.FECHA_INICIO.split('T')[0] : null,
    horasIngresadas: 0, horasEsperadas,
    _horasGlobales: horasGlobales, _fechaInicio: fechaInicio,
    _fechaFin: fechaFin, _fechaEjecucion: fechaEjecucion,
    _anioActual: anioActual, _diasObjetivo: diasObjetivo
  };
}

for (const r of registros) {
  const nAPI = limpiar(r.person);
  let matched = false;
  for (const key in consolidado) {
    if (nAPI === consolidado[key].NombreLimpio) {
      consolidado[key].horasIngresadas += Number(r.time || 0);
      matched = true; break;
    }
  }
  if (!matched) {
    const api3 = primPalabras(nAPI, 3);
    if (api3.length > 3) {
      for (const key in consolidado) {
        if (api3 === primPalabras(consolidado[key].NombreLimpio, 3)) {
          consolidado[key].horasIngresadas += Number(r.time || 0); break;
        }
      }
    }
  }
}

return Object.values(consolidado).map(p => ({ json: p }));

column684:
const c = $json;
const ing  = Math.round(Number(c.horasIngresadas) * 10) / 10;
const esp  = Number(c.horasEsperadas);
const dif  = Math.round((ing - esp) * 10) / 10;
const porc = esp > 0 ? Math.min(Math.floor((ing / esp) * 100), 100) : 0;

let est = '❌ Atrasado';
if (porc >= 95) est = '✅ Al día';
else if (porc >= 85) est = '⚠️ Pendiente';

return {
  ...c,
  horasEsperadas: esp, horasIngresadas: ing, diferencia: dif,
  porcentaje: porc, estado: est,
  semanasPendientes: porc < 100 ? Math.round((dif / 38.5) * 10) / 10 : 0
};

column691:
const datos = $input.all().sort((a, b) => Number(b.json.porcentaje) - Number(a.json.porcentaje));

const sample = datos[0]?.json || {};
const anioActual            = sample._anioActual || new Date().getFullYear();
const periodoInicio         = sample._fechaInicio || '';
const periodoFin            = sample._fechaFin || '';
const diasLaborables        = sample._diasObjetivo || 20;
const horasEsperadasPeriodo = sample._horasGlobales || 0;
const totalColaboradores    = datos.length;
const alDia      = datos.filter(i => i.json.estado === '✅ Al día').length;
const pendientes = datos.filter(i => i.json.estado === '⚠️ Pendiente').length;
const atrasados  = datos.filter(i => i.json.estado === '❌ Atrasado').length;

function esNuevoColab(d) {
  const v = d.json.NEW_COLAB;
  return v === true || v === 1 || String(v).toLowerCase() === 'true';
}

const normales      = datos.filter(d => !esNuevoColab(d));
const reciénIngreso = datos.filter(d => esNuevoColab(d));

function fmt(n) {
  const r = Math.round(Number(n) * 10) / 10;
  return Number.isInteger(r) ? r.toString() : r.toFixed(1);
}

function buildRow(d) {
  const cf = d.json.estado === '✅ Al día'    ? '#C9D6CC'
           : d.json.estado === '⚠️ Pendiente' ? '#E8DFC7'
           : '#F4CCCC';
  const cb = d.json.estado === '✅ Al día'    ? '#8BA88F'
           : d.json.estado === '⚠️ Pendiente' ? '#D4BC8E'
           : '#E89A9A';
  const ing         = Math.round(Number(d.json.horasIngresadas) * 10) / 10;
  const dif         = d.json.diferencia;
  const difDisplay  = fmt(Math.abs(dif));
  const porc        = d.json.porcentaje;
  const porcDisplay = `${porc}%`;
  const area        = d.json.AREA || 'N/A';
  let areaDisplay   = area;
  if (area === 'Favor actualizar')  areaDisplay = `<em style="color:#B8860B;font-weight:bold;">Favor actualizar</em>`;
  if (area === 'Área desconocida')  areaDisplay = `<em style="color:#CC0000;font-weight:bold;">Área desconocida</em>`;
  const tdStyle = `padding:4px 2px;height:20px;line-height:20px;border:1px solid ${cb};text-align:center;`;
  return `<tr>
    <td valign="middle" bgcolor="${cf}" style="${tdStyle}">${areaDisplay}</td>
    <td valign="middle" bgcolor="${cf}" style="${tdStyle}"><strong>${d.json.Nombre}</strong></td>
    <td valign="middle" bgcolor="${cf}" style="${tdStyle}"><strong>${fmt(ing)}</strong></td>
    <td valign="middle" bgcolor="${cf}" style="${tdStyle}"><strong>${fmt(d.json.horasEsperadas)}</strong></td>
    <td valign="middle" bgcolor="${cf}" style="${tdStyle}">${difDisplay}</td>
    <td valign="middle" bgcolor="${cf}" style="${tdStyle}">${porcDisplay}</td>
    <td valign="middle" bgcolor="${cf}" style="${tdStyle}"><strong>${d.json.estado}</strong></td>
    <td valign="middle" bgcolor="${cf}" style="${tdStyle}">${fmt(d.json.semanasPendientes || 0)}</td>
  </tr>`;
}

function buildTable(filas) {
  return `<table width="100%" cellpadding="0" cellspacing="0" border="1" bordercolor="#5838A3" style="width:100%;max-width:900px;border-collapse:collapse;font-size:12px;text-align:center;">
<colgroup><col style="width:14%"><col style="width:20%"><col style="width:12%"><col style="width:12%"><col style="width:10%"><col style="width:10%"><col style="width:13%"><col style="width:9%"></colgroup>
<thead><tr>
  <th valign="middle" bgcolor="#7049BC" style="border:1px solid #5838A3;color:#fff;padding:2px;">Área</th>
  <th valign="middle" bgcolor="#7049BC" style="border:1px solid #5838A3;color:#fff;padding:2px;">Colaborador</th>
  <th valign="middle" bgcolor="#7049BC" style="border:1px solid #5838A3;color:#fff;padding:2px;">Horas Ingresadas</th>
  <th valign="middle" bgcolor="#7049BC" style="border:1px solid #5838A3;color:#fff;padding:2px;">Horas Esperadas</th>
  <th valign="middle" bgcolor="#7049BC" style="border:1px solid #5838A3;color:#fff;padding:2px;">Diferencia</th>
  <th valign="middle" bgcolor="#7049BC" style="border:1px solid #5838A3;color:#fff;padding:2px;">Porcentaje</th>
  <th valign="middle" bgcolor="#7049BC" style="border:1px solid #5838A3;color:#fff;padding:2px;">Estado</th>
  <th valign="middle" bgcolor="#7049BC" style="border:1px solid #5838A3;color:#fff;padding:2px;">Semanas Pendientes</th>
</tr></thead>
<tbody>${filas.map(buildRow).join('')}</tbody></table>`;
}

const totalReciénIngreso = reciénIngreso.length;
const htmlCompleto = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:8px 10px;font-family:Arial,APTOS,sans-serif;font-size:12px;">
<h2 style="color:#7049BC;font-size:16px;margin:0;font-weight:bold;">Reporte de Horas – Año ${anioActual}</h2>
<p style="margin:8px 0;">Estimad@s, esperamos que este mensaje les encuentre bien:</p>
<p style="margin:8px 0;">Como formalidad semanal, se comparte el reporte de ingreso de horas correspondiente al período entre las fechas: <strong>${periodoInicio} al ${periodoFin}</strong>.</p>
<p style="margin:12px 0;"><span style="display:inline-block;background:#5CDB82;padding:10px;color:#000;"><strong>Nota:</strong> al momento de registrar las horas y su respectiva descripción, se solicita no utilizar signos especiales (como ", &amp;, %, entre otros), ya que estos afectan la reportería.</span></p>
${buildTable(normales)}
${reciénIngreso.length > 0 ? `<p style="color:#7049BC;font-size:14px;margin-top:24px;margin-bottom:8px;font-weight:bold;">Nuevos Colaboradores - Reintegración</p>${buildTable(reciénIngreso)}` : ''}
<p style="color:#7049BC;font-weight:bold;margin-top:18px;font-size:14px;">Alcances del Reporte:</p>
<ul style="margin:0;padding-left:18px;">
  <li>Fecha inicio: <strong>${periodoInicio}</strong></li><li>Fecha fin: <strong>${periodoFin}</strong></li>
  <li>Días hábiles considerados: <strong>${diasLaborables}</strong></li>
  <li>Horas contabilizadas en el período: <strong>${horasEsperadasPeriodo}</strong></li>
  <li>Total colaboradores: <strong>${totalColaboradores}</strong></li>
  <li>Colaboradores de reciente ingreso: <strong>${totalReciénIngreso}</strong></li>
  <li>Colaboradores al día: <strong>${alDia}</strong></li>
  <li>Colaboradores pendientes: <strong>${pendientes}</strong></li>
  <li>Colaboradores atrasados: <strong>${atrasados}</strong></li>
</ul>
<p style="margin-top:16px;">Frente a dudas, consultas o validación de métricas, comunicarse directamente con el <strong>área de control de gestión</strong>.</p>
<p style="margin-top:14px;">Saludos cordiales.<br>Equipo de Infraestructura.</p>
</body></html>`;

return [{ json: { htmlContent: htmlCompleto } }];

