column178:
const existingFiles = $('Combinar archivos1').first().json.name;
const currentFileName = items[0].binary.data.fileName;
const filesArray = Array.isArray(existingFiles) ? existingFiles : [existingFiles];
const fileExists = filesArray.includes(currentFileName);
return [{ json: { ...items[0].json, fileExists }, binary: items[0].binary }];

column472:
const content = items[0].binary.data.data;
const bytes = Buffer.from(content, 'base64');
const header = `blob ${bytes.length}\0`;
const store = Buffer.concat([Buffer.from(header), bytes]);
const crypto = require('crypto');
const shaLocal = crypto.createHash('sha1').update(store).digest('hex');
return [{ json: { shaLocal, fileName: 'colaboradores.csv' }, binary: items[0].binary }];

column571:
// El nodo Obtener SHA GitHub pisó el binario — lo recuperamos de Calcular SHA local
const binaryData = $('Calcular SHA local').first().binary;
return [{ json: items[0].json, binary: binaryData }];

column1577:
={{ (() => {
  const now = new Date(new Date().toLocaleString("en-US", {timeZone: "America/Santiago"}));
  const day = String(now.getDate()).padStart(2, '0');
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const year = now.getFullYear();
  const hours = String(now.getHours()).padStart(2, '0');
  const minutes = String(now.getMinutes()).padStart(2, '0');
  return `${day}-${month}-${year}/${hours}:${minutes}`;
})() }}

